const baseRaw = $items('Google Maps Text Search') || [];

// base
const base = baseRaw
  .map(i => i.json?.data || i.json)
  .flat()
  .flatMap(d => d.results || []);

// função pra normalizar texto
const normalizar = (str) =>
  (str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '') // remove acento
    .replace(/[^a-z0-9]/g, ''); // limpa tudo

// cria mapa com chave composta (nome + endereço)
const detailsMap = {};

($json.data || []).forEach(d => {
  const r = d.result || {};
  if (!r.name) return;

  const chave = normalizar(r.name);

  // guarda se tiver telefone ou site
  if (!detailsMap[chave] || r.formatted_phone_number || r.website) {
    detailsMap[chave] = r;
  }
});

// merge
const resultado = base.map(item => {
  const chave = normalizar(item.name);
  const det = detailsMap[chave] || {};

  return {
    nome: item?.name,
    tipo: item?.types?.[0],
    endereco: item?.formatted_address,
    latitude: item?.geometry?.location?.lat,
    longitude: item?.geometry?.location?.lng,
    aberto_agora: item?.opening_hours?.open_now ?? false,
    status: item?.business_status,
    avaliacao: item?.rating,
    total_avaliacoes: item?.user_ratings_total,

    telefone: det?.formatted_phone_number || null,
    site: det?.website || null
  };
});

return resultado.map(r => ({ json: r }));
